 1	import type { FC } from 'react';
 2	import { useNavigate } from 'react-router-dom-v5-compat';
 3	import { getResourceUrl } from 'src/modules/Providers/utils/helpers/getResourceUrl';
 4	import { useHasSufficientProviders } from 'src/utils/fetch';
 5	import { useForkliftTranslation } from 'src/utils/i18n';
 6	
 7	import { PlanModelRef } from '@kubev2v/types';
 8	import { Button, ButtonVariant, Tooltip } from '@patternfly/react-core';
 9	import { TELEMETRY_EVENTS } from '@utils/analytics/constants';
10	import { useForkliftAnalytics } from '@utils/analytics/hooks/useForkliftAnalytics';
11	
12	type PlansAddButtonProps = {
13	  namespace?: string;
14	  testId?: string;
15	  canCreate?: boolean;
16	};
17	
18	const PlansAddButton: FC<PlansAddButtonProps> = ({ canCreate, namespace, testId }) => {
19	  const { t } = useForkliftTranslation();
20	  const navigate = useNavigate();
21	  const { trackEvent } = useForkliftAnalytics();
22	  const hasSufficientProviders = useHasSufficientProviders(namespace);
23	
24	  const onClick = (event: React.MouseEvent<HTMLButtonElement>) => {
25	    event.preventDefault();
26	    event.stopPropagation();
27	
28	    trackEvent(TELEMETRY_EVENTS.PLAN_CREATE_BUTTON_CLICKED, {
29	      hasSufficientProviders,
30	      planNamespace: namespace,
31	    });
32	
33	    const planResourceUrl = getResourceUrl({
34	      namespaced: false,
35	      reference: PlanModelRef,
36	    });
37	
38	    navigate(`${planResourceUrl}/~new`);
39	  };
40	
41	  const button = (
42	    <Button
43	      data-testid={testId}
44	      variant={ButtonVariant.primary}
45	      isAriaDisabled={!hasSufficientProviders}
46	      onClick={onClick}
47	      isDisabled={!canCreate}
48	    >
49	      {t('Create plan')}
50	    </Button>
51	  );
52	
53	  if (hasSufficientProviders) return button;
54	
55	  return (
56	    <Tooltip
57	      content={
58	        namespace
59	          ? t(
60	              'At least one source and one target provider in the {{name}} project must be available.',
61	              { name: namespace },
62	            )
63	          : t('At least one source and one target provider must be available.')
64	      }
65	    >
66	      {button}
67	    </Tooltip>
68	  );
69	};
70	
71	export default PlansAddButton;

